import { describe, expect, test } from '@a0n/gnosis/test';
import { QDoc } from './qdoc';
import { QCorridor } from './qcorridor';

describe('QCorridor', () => {
  test('acts as a primitive for tunneling, settling, and path ranking', async () => {
    const doc = new QDoc({ guid: 'qcorridor-doc' });
    const corridor = new QCorridor(doc, { namespace: 'primitive' });
    const session = await corridor.createSession(
      'topology:shared-middle',
      {
        payload: 'seed',
      },
      {
        corridorKey: 'shared-middle',
        reuseScope: 'corridor',
      }
    );

    const firstLookup = corridor.lookup(session);
    expect(firstLookup.kind).toBe('miss');

    const inflight = Promise.resolve({ ok: true, value: 'seed -> settled' });
    corridor.registerInflight(session, inflight);
    const secondLookup = corridor.lookup<{ ok: boolean; value: string }>(
      session
    );
    expect(secondLookup.kind).toBe('tunnel');
    expect(secondLookup.kind === 'tunnel').toBe(true);

    await inflight;
    corridor.release(session);
    corridor.settle(
      session,
      { ok: true, value: 'seed -> settled' },
      {
        collapseCount: 1,
        firstSufficientCount: 1,
        ventCount: 1,
        repairDebt: 0,
        lastWinnerPath: 'fast',
      }
    );
    corridor.recordEvidence(session, [
      {
        path: 'fast',
        role: 'winner',
        status: 'success',
      },
      {
        path: 'slow',
        role: 'vent',
        status: 'cancelled',
      },
    ]);

    const hitLookup = corridor.lookup(session);
    expect(hitLookup.kind).toBe('hit');
    expect(corridor.rankPaths('shared-middle', ['slow', 'fast'])).toEqual([
      'fast',
      'slow',
    ]);
    expect(corridor.getCorridorStrength('shared-middle')).toBeGreaterThan(0);
    expect(corridor.getEvidence()).toHaveLength(2);
    expect(doc.toGG()).toContain('primitive_corridors');
  });

  test('requires cover when cached reuse leaves high residual route mass', async () => {
    const corridor = new QCorridor(new QDoc({ guid: 'qcorridor-cover' }), {
      namespace: 'cover',
    });
    const session = await corridor.createSession(
      'topology:finite-cover',
      { payload: 'seed' },
      {
        corridorKey: 'finite-cover',
        reuseScope: 'corridor',
        reuseAdmission: {
          minObservations: 3,
          residualBudget: 0,
        },
      }
    );

    expect(corridor.lookup(session).kind).toBe('miss');
    corridor.settle(
      session,
      { ok: true },
      {
        collapseCount: 1,
        firstSufficientCount: 1,
        ventCount: 2,
        repairDebt: 0,
        lastWinnerPath: 'fast',
      }
    );
    corridor.recordEvidence(session, [
      { path: 'fast', role: 'winner', status: 'success' },
      { path: 'slow', role: 'vent', status: 'cancelled' },
      { path: 'repair', role: 'repair', status: 'error' },
    ]);

    const admission = corridor.assessReuseAdmission(
      session,
      corridor.getEntry(session.requestKey)
    );
    expect(admission.admitted).toBe(false);
    expect(admission.decision).toBe('cover');
    expect(admission.witness?.residualMass).toBe(2);

    const coveredLookup = corridor.lookup(session);
    expect(coveredLookup.kind).toBe('miss');
    expect(corridor.getCorridor('finite-cover')?.cacheHits).toBe(0);
  });

  test('admits cached reuse and speculation from repeated finite route evidence', async () => {
    const reuseCorridor = new QCorridor(
      new QDoc({ guid: 'qcorridor-reuse-admit' }),
      { namespace: 'reuse' }
    );
    const reuseSession = await reuseCorridor.createSession(
      'topology:finite-reuse',
      { payload: 'seed' },
      {
        corridorKey: 'finite-reuse',
        reuseScope: 'corridor',
        reuseAdmission: {
          minObservations: 3,
          minConcentrationBps: 10_000,
          residualBudget: 0,
        },
      }
    );

    expect(reuseCorridor.lookup(reuseSession).kind).toBe('miss');
    reuseCorridor.settle(
      reuseSession,
      { ok: true, path: 'fast' },
      {
        collapseCount: 1,
        firstSufficientCount: 1,
        ventCount: 0,
        repairDebt: 0,
        lastWinnerPath: 'fast',
      }
    );
    reuseCorridor.recordEvidence(reuseSession, [
      { path: 'fast', role: 'winner', status: 'success' },
      { path: 'fast', role: 'winner', status: 'success' },
      { path: 'fast', role: 'winner', status: 'success' },
    ]);

    const reuseAdmission = reuseCorridor.assessReuseAdmission(
      reuseSession,
      reuseCorridor.getEntry(reuseSession.requestKey)
    );
    expect(reuseAdmission.admitted).toBe(true);
    expect(reuseAdmission.decision).toBe('reuse');
    expect(reuseCorridor.lookup(reuseSession).kind).toBe('hit');

    const speculateCorridor = new QCorridor(
      new QDoc({ guid: 'qcorridor-speculate-admit' }),
      { namespace: 'speculate' }
    );
    const speculateSession = await speculateCorridor.createSession(
      'topology:finite-speculate',
      { payload: 'seed' },
      {
        corridorKey: 'finite-speculate',
        reuseScope: 'corridor',
        reuseAdmission: {
          minObservations: 3,
          minConcentrationBps: 9_000,
          residualBudget: 1,
        },
      }
    );

    expect(speculateCorridor.lookup(speculateSession).kind).toBe('miss');
    speculateCorridor.settle(
      speculateSession,
      { ok: true, path: 'fast' },
      {
        collapseCount: 1,
        firstSufficientCount: 1,
        ventCount: 1,
        repairDebt: 0,
        lastWinnerPath: 'fast',
      }
    );
    speculateCorridor.recordEvidence(speculateSession, [
      { path: 'fast', role: 'winner', status: 'success' },
      { path: 'fast', role: 'winner', status: 'success' },
      { path: 'slow', role: 'vent', status: 'cancelled' },
    ]);

    const speculation = speculateCorridor.assessReuseAdmission(
      speculateSession,
      speculateCorridor.getEntry(speculateSession.requestKey)
    );
    expect(speculation.admitted).toBe(true);
    expect(speculation.decision).toBe('speculate');
    expect(speculateCorridor.lookup(speculateSession).kind).toBe('hit');
    expect(
      speculateCorridor.rankPaths('finite-speculate', ['slow', 'fast'], {
        minObservations: 3,
        minConcentrationBps: 9_000,
        residualBudget: 1,
      })
    ).toEqual(['fast', 'slow']);
  });
});
